mapper.select:
SELECT FROM fridge_item WHERE member_id = #{memberId}
AND storage_type = #{storageType}
ORDER BY created_at DESC ORDER BY name ASC ORDER BY expiry_date ASC

SELECT 
  FROM fridge_item
 WHERE member_id = #{memberId}
   AND DATEDIFF(expiry_date, CURDATE()) <= #{days}
 ORDER BY expiry_date ASC

SELECT member_id FROM fridge_item
 WHERE fridge_item_id = #{fridgeItemId}
 LIMIT 1

SELECT ri.ingredient_id
  FROM recipe_ingredient ri
 WHERE ri.recipe_id = #{recipeId}
   AND EXISTS (
       SELECT 1 FROM fridge_item fi
        WHERE fi.member_id = #{memberId}
          AND fi.name = ri.name
   )
